// Idempotent event processor with deduplication
async function processEvent(event) {
  const cacheKey = `event:${event.event_id}`;

  if (await redis.setnx(cacheKey, 'processing')) {
    try {
      await redis.expire(cacheKey, 86400); // 24-hour TTL
      await processInOrder(event);
    } finally {
      await redis.del(cacheKey);
    }
  } else {
    await sendToDLQ(event, 'duplicate');
  }
}

// Monotonic timestamp enforcement
function enforceMonotonic(event, sourceState) {
  if (event.timestamp >= sourceState.lastTimestamp) {
    sourceState.lastTimestamp = event.timestamp;
    return event;
  }
  return null; // Reject out-of-order event
}
```

