// Sketch of per-region breaker state
class RegionalBreaker {
  constructor(threshold, windowMs = 60000) {
    this.threshold = threshold;
    this.window = windowMs;
    this.failures = 0;
    this.successes = 0;
    this.state = 'CLOSED';
    this.lastFailureTime = 0;
  }

  recordSuccess() {
    this.successes++;
    if (this.state === 'HALF_OPEN' && this.successes > this.threshold) {
      this.state = 'CLOSED';
      this.failures = 0;
      this.successes = 0;
    }
  }

  recordFailure() {
    this.failures++;
    this.lastFailureTime = Date.now();
    const errorRate = this.failures / (this.failures + this.successes);
    if (errorRate >= this.threshold) {
      this.state = 'OPEN';
    }
  }

  canAttemptRequest() {
    if (this.state === 'OPEN') {
      const timeSinceFailure = Date.now() - this.lastFailureTime;
      if (timeSinceFailure > this.window) {
        this.state = 'HALF_OPEN';
        return true;
      }
      return false;
    }
    return true;
  }
}

// Token bucket quota per region
class RegionalQuota {
  constructor(maxTokens, refillRate) {
    this.tokens = maxTokens;
    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  tryConsume(tokens = 1) {
    this.refill();
    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  refill() {
    const now = Date.now();
    const tokensToAdd = (now - this.lastRefill) * this.refillRate / 1000;
    this.tokens = Math.min(this.maxTokens, this.tokens + tokensToAdd);
    this.lastRefill = now;
  }
}
```

This implementation provides:
- **Circuit Breaker**: Tracks failure rates and transitions between CLOSED, OPEN, and HALF_OPEN states
- **Token Bucket Quota**: Enforces rate limits per region with configurable refill rates
- **Observable Metrics**: Both classes support instrumentation for monitoring p95 latency, error rates, and quota utilization

